impl eframe::App for EditorApp { fn update(&mut self, ctx: &egui::Context, _frame: &mut eframe::Frame) { egui::TopBottomPanel::top("top_panel").show(ctx, |ui| { ui.horizontal(|ui| { ui.label("Editor de Código"); ui.separator(); ui.label(format!("Archivo: {}", self.api.active_buffer)); }); }); egui::CentralPanel::default().show(ctx, |ui| { let text_edit = egui::TextEdit::multiline(&mut self.api.buffers.get_mut(&self.api.active_buffer).unwrap().lines[0]) .desired_width(f32::INFINITY); ui.add_sized(ui.available_size(), text_edit); }); } fn on_exit(&mut self, _gl: Option<&eframe::glow::Context>) { println!("Guardando..."); } }
